   277→  };
   278→  const baseHeading = candidates.find(isStructuralHeading);
   279→  // When the initial heading has a continuation on the next line introduced by a punctuation token
   280→  // (/, &, +, :, or parenthesis), prefer the longer 2-line join as the complete heading.
   281→  // E.g. "SAFFRON WHEAT BUNS WITH QUARK" + "/ COTTAGE CHEESE (VARIATION D)" → prefers the join.
   282→  // Guard: the remainder after the prefix must start with a continuation character to avoid
   283→  // merging two separate consecutive recipe titles (FINNISH MILK FLATBREADS stays separate
   284→  // from FINNISH POTATO FLATBREADS because "FINNISH" does not start with a continuation token).
   285→  const firstStructuralHeading = baseHeading && (
   286→    candidates.find((c) => {
   287→      if (!isStructuralHeading(c)) return false;
   288→      const hLower = baseHeading.text.toLowerCase();
   289→      const cLower = c.text.toLowerCase();
   290→      return cLower.startsWith(hLower + " ") && /^[/&+:(]/.test(cLower.slice(hLower.length + 1));
   291→    }) ?? baseHeading
   292→  );
